const { DynamoDBClient, UpdateItemCommand } = require("@aws-sdk/client-dynamodb");
const { SQSHandler } = require("aws-lambda");
const https = require("https");
const http = require("http");
const { URL } = require("url");

const ddb = new DynamoDBClient({});
const ORDERS_TABLE = process.env.ORDERS_TABLE;
const PAYMENT_API_URL = process.env.PAYMENT_API_URL;

function requestJson(method, targetUrl, body, headers = {}) {
  return new Promise((resolve, reject) => {
    const url = new URL(targetUrl);
    const isHttps = url.protocol === "https:";
    const lib = isHttps ? https : http;

    const payload = body ? JSON.stringify(body) : undefined;

    const options = {
      method,
      hostname: url.hostname,
      port: url.port || (isHttps ? 443 : 80),
      path: `${url.pathname}${url.search}`,
      headers: {
        "Content-Type": "application/json",
        ...(payload ? { "Content-Length": Buffer.byteLength(payload) } : {}),
        ...headers,
      },
      timeout: 5000,
    };

    const req = lib.request(options, (res) => {
      let data = "";
      res.on("data", (chunk) => (data += chunk));
      res.on("end", () => {
        let parsed = data;
        try {
          parsed = data ? JSON.parse(data) : {};
        } catch (_) {}
        if (res.statusCode >= 200 && res.statusCode < 300) {
          resolve(parsed);
        } else {
          reject(new Error(`HTTP ${res.statusCode}: ${data}`));
        }
      });
    });

    req.on("error", reject);
    req.on("timeout", () => {
      req.destroy(new Error("Request timeout"));
    });

    if (payload) req.write(payload);
    req.end();
  });
}

async function callPaymentApi(order) {
  return requestJson("POST", PAYMENT_API_URL, {
    orderId: order.orderId,
    amount: order.amount,
    currency: order.currency,
    customerId: order.customerId,
  });
}

async function updateOrderStatus(orderId, status, paymentResult = {}) {
  await ddb.send(
    new UpdateItemCommand({
      TableName: ORDERS_TABLE,
      Key: {
        orderId: { S: orderId },
      },
      UpdateExpression:
        "SET #status = :status, updatedAt = :updatedAt, paymentResult = :paymentResult",
      ExpressionAttributeNames: {
        "#status": "status",
      },
      ExpressionAttributeValues: {
        ":status": { S: status },
        ":updatedAt": { S: new Date().toISOString() },
        ":paymentResult": { S: JSON.stringify(paymentResult) },
      },
    })
  );
}

exports.handler = async (event) => {
  const records = event.Records || [];

  for (const record of records) {
    try {
      const order = JSON.parse(record.body);

      let paymentResult = {};
      try {
        paymentResult = await callPaymentApi(order);
      } catch (err) {
        console.error("Payment API error", {
          orderId: order?.orderId,
          error: err.message,
        });
        await updateOrderStatus(order.orderId, "PAYMENT_FAILED", {
          error: err.message,
        });
        continue;
      }

      try {
        await updateOrderStatus(order.orderId, "PAID", paymentResult);
      } catch (err) {
        console.error("DynamoDB update error", {
          orderId: order?.orderId,
          error: err.message,
        });
      }
    } catch (err) {
      console.error("Record processing error", {
        error: err.message,
        body: record.body,
      });
      continue;
    }
  }

  return {
    statusCode: 200,
    processed: records.length,
  };
};